    def __init__(self, protos):
        self.protos = protos

    @classmethod
    def load(cls):
        # 데이터 numpy로 변환해서 로드
        protos = []
        for char, (w, h, data) in cls.RAW_DATA.items():
            protos.append((char, np.array(data, dtype=np.uint8).reshape((h, w))))
        return cls(protos)

    def solve(self, img_bytes):
        detailed = self.solve_detailed(img_bytes)
        return "".join(c for c, _ in detailed)

    def solve_detailed(self, img_bytes):
        # 1. 이미지 읽고 이진화 (배경 날림)
        raw = Image.open(io.BytesIO(img_bytes)).convert("RGBA")
        width, height = raw.size
        
        bg = Image.new("RGBA", raw.size, (255, 255, 255, 255))
        composite = Image.alpha_composite(bg, raw).convert("L")
        binary_arr = (np.array(composite) < 150).astype(np.uint8)

        # 2. 노이즈 바 제거
        noise_rows = set()
        for y in range(min(height, 30)):
            if np.sum(binary_arr[y, :]) / width > 0.6:
                noise_rows.add(y)

        # 3. 커닝 데이터
        def get_advance(c):
            if c in ('1', '5'): return 18
            if c in ('6', '7', '8'): return 19
            return 20

        def get_bearing(c):
            if c == '1': return 2
            if c in ('5', '6', '7', '8'): return 1
            return 0

        used_digits = set()
        result = []
        last_x = 0
        last_char = ' '

        for slot in range(6):
            slot_best_char = '?'
            slot_best_score = float('-inf')
            slot_best_x = 0

            for char, proto in self.protos:
                if char in used_digits: continue

                ph, pw = proto.shape
                reachable_mask = np.ones(ph, dtype=bool)
                for r in noise_rows:
                    if r < ph: reachable_mask[r] = False
                
                valid_proto = proto[reachable_mask, :]
                reachable = np.sum(valid_proto)
                if reachable == 0: continue

                # 커닝 기반 위치 예측
                if slot == 0:
                    search_offsets = range(9, 12)
                else:
                    base = last_x + get_advance(last_char) + get_bearing(char)
                    search_offsets = range(base - 2, base + 3)

                for offset in search_offsets:
                    if offset < 0 or offset + pw > width: continue

                    target_chunk = binary_arr[:ph, offset:offset+pw][reachable_mask, :]
                    
                    hit = np.sum((valid_proto == 1) & (target_chunk == 1))
                    miss = np.sum((valid_proto == 1) & (target_chunk == 0))
                    noise = np.sum((valid_proto == 0) & (target_chunk == 1))

                    score = (hit - miss * 2.0 - noise * 1.5) / reachable
                    if score > slot_best_score:
                        slot_best_score = score
                        slot_best_char = char
                        slot_best_x = offset

            if slot_best_char != '?':
                result.append((slot_best_char, slot_best_x))
                used_digits.add(slot_best_char)
                last_x = slot_best_x
                last_char = slot_best_char
            else:
                result.append(('?', 0))

        return result
